module power_gating (  
    input wire disable_signal,  
    input wire [3:0] data_input,  
    output reg [3:0] data_output  
);  
    always @(*) begin  
        if (disable_signal)  
            data_output = data_input;  
        else  
            data_output = 4'b0000;  
    end  
endmodule
